class Solution:
    def frogPosition(self, n, edges, t, target):
        from collections import defaultdict
        graph = defaultdict(list)
        for u, v in edges:
            graph[u].append(v)
            graph[v].append(u)
        # BFS-based brute force: track (node, prob, time, parent)
        # Use DFS with explicit stack
        stack = [(1, 1.0, 0, -1)]
        while stack:
            node, prob, time, parent = stack.pop()
            children = [nb for nb in graph[node] if nb != parent]
            if node == target:
                if time == t or not children:
                    return prob
                return 0.0
            if time < t and children:
                for ch in children:
                    stack.append((ch, prob / len(children), time + 1, node))
        return 0.0

