class Solution:
    def frogPosition(self, n, edges, t, target):
        from collections import defaultdict, deque
        if n == 1:
            return 1.0
        graph = defaultdict(list)
        for u, v in edges:
            graph[u].append(v)
            graph[v].append(u)
        visited = [False] * (n + 1)
        visited[1] = True
        queue = deque([(1, 1.0)])
        for step in range(t):
            for _ in range(len(queue)):
                node, prob = queue.popleft()
                children = [nb for nb in graph[node] if not visited[nb]]
                if node == target:
                    if not children:
                        return prob
                    return 0.0
                for ch in children:
                    visited[ch] = True
                    queue.append((ch, prob / len(children)))
        for node, prob in queue:
            if node == target:
                return prob
        return 0.0

