var frogPosition = function(n, edges, t, target) {
    if (n === 1) return 1.0;
    const graph = Array.from({length: n + 1}, () => []);
    for (const [u, v] of edges) {
        graph[u].push(v);
        graph[v].push(u);
    }
    const visited = new Array(n + 1).fill(false);
    visited[1] = true;
    let queue = [[1, 1.0]];
    for (let step = 0; step < t; step++) {
        const next = [];
        for (const [node, prob] of queue) {
            const children = graph[node].filter(nb => !visited[nb]);
            if (node === target) {
                if (children.length === 0) return prob;
                return 0.0;
            }
            for (const ch of children) {
                visited[ch] = true;
                next.push([ch, prob / children.length]);
            }
        }
        queue = next;
    }
    for (const [node, prob] of queue) {
        if (node === target) return prob;
    }
    return 0.0;
};
